body.script:
//
/* ── Mobile Nav ── */
function openMobileNav(){document.getElementById('mobile-nav').classList.add('open');document.getElementById('mobileOverlay').classList.add('show')}
function closeMobileNav(){document.getElementById('mobile-nav').classList.remove('open');document.getElementById('mobileOverlay').classList.remove('show')}
function toggleMobileSub(el){const sub=el.nextElementSibling;if(sub){sub.classList.toggle('open')}}

/* ── Back To Top ── */
window.addEventListener('scroll',function(){
  const btn=document.getElementById('back-to-top');
  btn.classList.toggle('show',window.scrollY>300);
});

/* ── Hero Slider ── */
(function(){
  let slides=document.querySelectorAll('.hero-slide');
  let current=0;
  let autoInterval;
  function goTo(n){
    slides.forEach(s=>s.classList.remove('active'));
    current=(n+slides.length)%slides.length;
    if(slides[current]) slides[current].classList.add('active');
  }
  if(slides.length>1){
    autoInterval=setInterval(function(){goTo(current+1);},5000);
  }
  // Expose for buttons
  window.heroNext=function(){clearInterval(autoInterval);goTo(current+1);autoInterval=setInterval(function(){goTo(current+1);},5000);};
  window.heroPrev=function(){clearInterval(autoInterval);goTo(current-1);autoInterval=setInterval(function(){goTo(current+1);},5000);};
})();

/* ── Filter Tabs ── */
document.querySelectorAll('.filter-tab').forEach(function(tab){
  tab.addEventListener('click',function(){
    document.querySelectorAll('.filter-tab').forEach(t=>t.classList.remove('active'));
    this.classList.add('active');
    var label=this.getAttribute('data-label');
    if(label){
      window.location.href='/search/label/'+encodeURIComponent(label);
    }else{
      window.location.href='/';
    }
  });
});

/* ── Related Posts via Blogger JSON API ── */
(function(){
  var container=document.getElementById('relatedPosts');
  if(!container) return;
  var labels=document.querySelectorAll('.post-tags .tag');
  if(!labels.length) return;
  var lbl=labels[0].textContent.trim();
  var script=document.createElement('script');
  var callbackName='relatedPostsCallback_'+Date.now();
  window[callbackName]=function(data){
    if(!data.feed || !data.feed.entry) return;
    var html='';
    data.feed.entry.slice(0,8).forEach(function(entry){
      var title=entry.title.$t;
      var link=entry.link.find(function(l){return l.rel==='alternate';});
      var url=link?link.href:'#';
      var thumb='';
      if(entry.media$thumbnail) thumb=entry.media$thumbnail.url.replace('s72-c','s300-c');
      html+='<article class="post-card"><a class="card-thumb" href="'+url+'">'+(thumb?'<img src="'+thumb+'" alt="'+title+'" loading="lazy"/>':"")+'<div class="card-overlay"><div class="card-play-btn"><i class="fas fa-play"></i></div></div></a><div class="card-body"><h3 class="card-title"><a href="'+url+'">'+title+'</a></h3></div></article>';
    });
    container.innerHTML=html;
  };
  script.src='/feeds/posts/default/-/'+encodeURIComponent(lbl)+'?alt=json-in-script&max-results=8&callback='+callbackName;
  document.body.appendChild(script);
})();

/* ── Ticker via Blogger JSON API ── */
(function(){
  var ticker=document.getElementById('tickerScroll');
  if(!ticker) return;
  var script=document.createElement('script');
  var cb='tickerCb_'+Date.now();
  window[cb]=function(data){
    if(!data.feed||!data.feed.entry) return;
    var html='';
    var items=data.feed.entry;
    // duplicate for seamless scroll
    [items,items].forEach(function(arr){
      arr.forEach(function(e){
        var lnk=e.link.find(function(l){return l.rel==='alternate';});
        var url=lnk?lnk.href:'#';
        html+='<a href="'+url+'">🎬 '+e.title.$t+'</a>';
      });
    });
    ticker.innerHTML=html;
  };
  script.src='/feeds/posts/default?alt=json-in-script&max-results=15&callback='+cb;
  document.body.appendChild(script);
})();

/* ── Lazy load images fallback ── */
if('loading' in HTMLImageElement.prototype){
  // Native lazy loading supported
}else{
  var lazyImages=document.querySelectorAll('img[loading="lazy"]');
  var imageObserver=new IntersectionObserver(function(entries){
    entries.forEach(function(entry){
      if(entry.isIntersecting){
        var img=entry.target;
        if(img.dataset.src) img.src=img.dataset.src;
        imageObserver.unobserve(img);
      }
    });
  });
  lazyImages.forEach(function(img){imageObserver.observe(img);});
}
//
